import React, { useState } from "react";
import Form from "./components/Form";
import Preview from "./components/Preview";

function App() {
  const [data, setData] = useState({
  name: "",
  email: "",
  phone: "",
  skills: "",
  education: [
    { college: "", degree: "", year: "" }
  ]
});

  return (
    <div style={{ display: "flex", padding: "20px" }}>
      <Form data={data} setData={setData} />
      <Preview data={data} />
    </div>
  );
}

export default App;
